{
  "$schema": "https://vega.github.io/schema/vega-lite/v5.json",
  "description": "A scatterplot showing the relationship between US Gross and Worldwide Gross of movies.",
  "data": {"url": "artifacts/preprocessed_data.csv"},
  "mark": "point",
  "encoding": {
    "x": {
      "field": "US_Gross",
      "type": "quantitative",
      "title": "US Gross"
    },
    "y": {
      "field": "Worldwide_Gross",
      "type": "quantitative",
      "title": "Worldwide Gross"
    },
    "tooltip": [
      {"field": "Title", "type": "nominal"},
      {"field": "US_Gross", "type": "quantitative"},
      {"field": "Worldwide_Gross", "type": "quantitative"}
    ]
  }
}
